    # We'll use a hash to ensure uniqueness and validity
    combined_string = f"{user_id}_{full_path}"
    # Use MD5 hash to create a unique, fixed-length, valid suffix
    # This avoids issues with very long paths or special characters
    hash_suffix = hashlib.md5(combined_string.encode('utf-8')).hexdigest()
    return f"http_requests_user_path_count_{hash_suffix}"

